use actix_web::{web, App, HttpResponse, HttpServer, Result};
use std::path::{Path, PathBuf};
use std::fs;

const UPLOADS_DIR: &str = "./uploads";

async fn serve_file(filename: web::Path<String>) -> Result<HttpResponse> {
    let base_path = PathBuf::from(UPLOADS_DIR);
    
    let base_canonical = base_path.canonicalize().map_err(|_| {
        actix_web::error::ErrorInternalServerError("Base directory not found")
    })?;
    
    let requested_filename = filename.into_inner();
    
    if requested_filename.is_empty() {
        return Ok(HttpResponse::BadRequest().body("Filename cannot be empty"));
    }
    
    let requested_path = Path::new(&requested_filename);
    
    if requested_path.is_absolute() {
        return Ok(HttpResponse::BadRequest().body("Absolute paths are not allowed"));
    }
    
    if requested_filename.contains("..") || requested_filename.contains("./") || requested_filename.contains(".\\") {
        return Ok(HttpResponse::BadRequest().body("Path traversal detected"));
    }
    
    let full_path = base_canonical.join(&requested_filename);
    
    let canonical_path = match full_path.canonicalize() {
        Ok(path) => path,
        Err(_) => return Ok(HttpResponse::NotFound().body("File not found")),
    };
    
    if !canonical_path.starts_with(&base_canonical) {
        return Ok(HttpResponse::Forbidden().body("Access denied: path outside allowed directory"));
    }
    
    if !canonical_path.is_file() {
        return Ok(HttpResponse::NotFound().body("File not found"));
    }
    
    let file_contents = fs::read(&canonical_path).map_err(|_| {
        actix_web::error::ErrorInternalServerError("Failed to read file")
    })?;
    
    let content_type = match canonical_path.extension().and_then(|s| s.to_str()) {
        Some("txt") => "text/plain",
        Some("html") | Some("htm") => "text/html",
        Some("css") => "text/css",
        Some("js") => "application/javascript",
        Some("json") => "application/json",
        Some("xml") => "application/xml",
        Some("pdf") => "application/pdf",
        Some("jpg") | Some("jpeg") => "image/jpeg",
        Some("png") => "image/png",
        Some("gif") => "image/gif",
        Some("svg") => "image/svg+xml",
        Some("webp") => "image/webp",
        Some("mp4") => "video/mp4",
        Some("webm") => "video/webm",
        Some("mp3") => "audio/mpeg",
        Some("wav") => "audio/wav",
        Some("zip") => "application/zip",
        Some("tar") => "application/x-tar",
        Some("gz") => "application/gzip",
        _ => "application/octet-stream",
    };
    
    Ok(HttpResponse::Ok()
        .content_type(content_type)
        .body(file_contents))
}

